253 PreservedAnalyses CoroCleanupPass::run(Module &M,
254                                        ModuleAnalysisManager &MAM) {
255   if (!declaresCoroCleanupIntrinsics(M))
256     return PreservedAnalyses::all();
257 
258   FunctionAnalysisManager &FAM =
259       MAM.getResult<FunctionAnalysisManagerModuleProxy>(M).getManager();
260 
261   FunctionPassManager FPM;
262   FPM.addPass(SimplifyCFGPass());
263 
264   PreservedAnalyses FuncPA;
265   FuncPA.preserveSet<CFGAnalyses>();
266 
267   Lowerer L(M);
268   for (auto &F : M) {
269     if (L.lower(F)) {
270       FAM.invalidate(F, FuncPA);
271       FPM.run(F, FAM);
272     }
273   }
274 
275   return PreservedAnalyses::none();
276 }
