296     case Intrinsic::fake_use:
297       PI.setEscaped(&II);
298       return;
299 
300     case Intrinsic::lifetime_start:
301     case Intrinsic::lifetime_end:
302       return; // No-op intrinsics.
303     }
304   }
305 
306   // Generically, arguments to calls and invokes escape the pointer to some
307   // other function. Mark that.
308   void visitCallBase(CallBase &CB) {
309     PI.setEscaped(&CB);
310     Base::visitCallBase(CB);
311   }
312 };
