 58 static void lowerSubFn(IRBuilder<> &Builder, CoroSubFnInst *SubFn) {
 59   Builder.SetInsertPoint(SubFn);
 60   Value *FramePtr = SubFn->getFrame();
 61   int Index = SubFn->getIndex();
 62 
 63   auto *FrameTy = StructType::get(SubFn->getContext(),
 64                                   {Builder.getPtrTy(), Builder.getPtrTy()});
 65 
 66   Builder.SetInsertPoint(SubFn);
 67   auto *Gep = Builder.CreateConstInBoundsGEP2_32(FrameTy, FramePtr, 0, Index);
 68   auto *Load = Builder.CreateLoad(FrameTy->getElementType(Index), Gep);
 69 
 70   SubFn->replaceAllUsesWith(Load);
 71 }
