 73 static void buildDebugInfoForNoopResumeDestroyFunc(Function *NoopFn) {
 74   Module &M = *NoopFn->getParent();
 75   if (M.debug_compile_units().empty())
 76     return;
 77 
 78   DICompileUnit *CU = *M.debug_compile_units_begin();
 79   DIBuilder DB(M, /*AllowUnresolved*/ false, CU);
 80   std::array<Metadata *, 2> Params{nullptr, nullptr};
 81   auto *SubroutineType =
 82       DB.createSubroutineType(DB.getOrCreateTypeArray(Params));
 83   StringRef Name = NoopFn->getName();
 84   auto *SP = DB.createFunction(
 85       CU, /*Name=*/Name, /*LinkageName=*/Name, /*File=*/CU->getFile(),
 86       /*LineNo=*/0, SubroutineType, /*ScopeLine=*/0, DINode::FlagArtificial,
 87       DISubprogram::SPFlagDefinition);
 88   NoopFn->setSubprogram(SP);
 89   DB.finalize();
 90 }
