 92 bool Lowerer::lower(Function &F) {
 93   bool IsPrivateAndUnprocessed = F.isPresplitCoroutine() && F.hasLocalLinkage();
 94   bool Changed = false;
 95 
 96   NoopCoroElider NCE(F.getDataLayout(), F.getContext());
 97   SmallPtrSet<Instruction *, 8> DeadInsts{};
 98   for (Instruction &I : instructions(F)) {
 99     if (auto *II = dyn_cast<IntrinsicInst>(&I)) {
100       switch (II->getIntrinsicID()) {
101       default:
102         continue;
103       case Intrinsic::coro_begin:
104       case Intrinsic::coro_begin_custom_abi:
105         II->replaceAllUsesWith(II->getArgOperand(1));
106         break;
107       case Intrinsic::coro_free:
108         II->replaceAllUsesWith(II->getArgOperand(1));
109         break;
110       case Intrinsic::coro_alloc:
111         II->replaceAllUsesWith(ConstantInt::getTrue(Context));
112         break;
113       case Intrinsic::coro_async_resume:
114         II->replaceAllUsesWith(
115             ConstantPointerNull::get(cast<PointerType>(I.getType())));
116         break;
117       case Intrinsic::coro_id:
118       case Intrinsic::coro_id_retcon:
119       case Intrinsic::coro_id_retcon_once:
120       case Intrinsic::coro_id_async:
121         II->replaceAllUsesWith(ConstantTokenNone::get(Context));
122         break;
123       case Intrinsic::coro_noop:
124         NCE.run(II);
125         if (!II->user_empty())
126           lowerCoroNoop(II);
127         break;
128       case Intrinsic::coro_subfn_addr:
129         lowerSubFn(Builder, cast<CoroSubFnInst>(II));
130         break;
131       case Intrinsic::coro_suspend_retcon:
132       case Intrinsic::coro_is_in_ramp:
133         if (IsPrivateAndUnprocessed) {
134           II->replaceAllUsesWith(PoisonValue::get(II->getType()));
135         } else
136           continue;
137         break;
138       case Intrinsic::coro_async_size_replace:
139         auto *Target = cast<ConstantStruct>(
140             cast<GlobalVariable>(II->getArgOperand(0)->stripPointerCasts())
141                 ->getInitializer());
142         auto *Source = cast<ConstantStruct>(
143             cast<GlobalVariable>(II->getArgOperand(1)->stripPointerCasts())
144                 ->getInitializer());
145         auto *TargetSize = Target->getOperand(1);
146         auto *SourceSize = Source->getOperand(1);
147         if (TargetSize->isElementWiseEqual(SourceSize)) {
148           break;
149         }
150         auto *TargetRelativeFunOffset = Target->getOperand(0);
151         auto *NewFuncPtrStruct = ConstantStruct::get(
152             Target->getType(), TargetRelativeFunOffset, SourceSize);
153         Target->replaceAllUsesWith(NewFuncPtrStruct);
154         break;
155       }
156       DeadInsts.insert(II);
157       Changed = true;
158     }
159   }
160 
161   for (auto *I : DeadInsts)
162     I->eraseFromParent();
163   return Changed;
164 }
