166 void Lowerer::lowerCoroNoop(IntrinsicInst *II) {
167   if (!NoopCoro) {
168     LLVMContext &C = Builder.getContext();
169     Module &M = *II->getModule();
170 
171     // Create a noop.frame struct type.
172     auto *FnTy = FunctionType::get(Type::getVoidTy(C), Builder.getPtrTy(0),
173                                    /*isVarArg=*/false);
174     auto *FnPtrTy = Builder.getPtrTy(0);
175     StructType *FrameTy =
176         StructType::create({FnPtrTy, FnPtrTy}, "NoopCoro.Frame");
177 
178     // Create a Noop function that does nothing.
179     Function *NoopFn = Function::createWithDefaultAttr(
180         FnTy, GlobalValue::LinkageTypes::InternalLinkage,
181         M.getDataLayout().getProgramAddressSpace(), "__NoopCoro_ResumeDestroy",
182         &M);
183     NoopFn->setCallingConv(CallingConv::Fast);
184     buildDebugInfoForNoopResumeDestroyFunc(NoopFn);
185     auto *Entry = BasicBlock::Create(C, "entry", NoopFn);
186     ReturnInst::Create(C, Entry);
187 
188     // Create a constant struct for the frame.
189     Constant *Values[] = {NoopFn, NoopFn};
190     Constant *NoopCoroConst = ConstantStruct::get(FrameTy, Values);
191     NoopCoro = new GlobalVariable(
192         M, NoopCoroConst->getType(), /*isConstant=*/true,
193         GlobalVariable::PrivateLinkage, NoopCoroConst, "NoopCoro.Frame.Const");
194     cast<GlobalVariable>(NoopCoro)->setNoSanitizeMetadata();
195   }
196 
197   Builder.SetInsertPoint(II);
198   auto *NoopCoroVoidPtr = Builder.CreateBitCast(NoopCoro, Int8Ptr);
199   II->replaceAllUsesWith(NoopCoroVoidPtr);
200 }
