209 void NoopCoroElider::visitCallBase(CallBase &CB) {
210   auto *V = U->get();
211   bool ResumeOrDestroy = V == CB.getCalledOperand();
212   if (ResumeOrDestroy) {
213     [[maybe_unused]] bool Success = tryEraseCallInvoke(&CB);
214     assert(Success && "Unexpected CallBase");
215     RecursivelyDeleteTriviallyDeadInstructions(V);
216   }
217 }
