219 void NoopCoroElider::visitIntrinsicInst(IntrinsicInst &II) {
220   if (auto *SubFn = dyn_cast<CoroSubFnInst>(&II)) {
221     auto *User = SubFn->getUniqueUndroppableUser();
222     if (!tryEraseCallInvoke(cast<Instruction>(User)))
223       return;
224     SubFn->eraseFromParent();
225   }
226 }
227 
228 bool NoopCoroElider::tryEraseCallInvoke(Instruction *I) {
229   if (auto *Call = dyn_cast<CallInst>(I)) {
230     Call->eraseFromParent();
231     return true;
232   }
233 
234   if (auto *II = dyn_cast<InvokeInst>(I)) {
235     Builder.SetInsertPoint(II);
236     Builder.CreateBr(II->getNormalDest());
237     II->eraseFromParent();
238     return true;
239   }
240   return false;
241 }
