243 static bool declaresCoroCleanupIntrinsics(const Module &M) {
244   return coro::declaresIntrinsics(
245       M,
246       {Intrinsic::coro_alloc, Intrinsic::coro_begin, Intrinsic::coro_subfn_addr,
247        Intrinsic::coro_free, Intrinsic::coro_id, Intrinsic::coro_id_retcon,
248        Intrinsic::coro_id_async, Intrinsic::coro_id_retcon_once,
249        Intrinsic::coro_noop, Intrinsic::coro_async_size_replace,
250        Intrinsic::coro_async_resume, Intrinsic::coro_begin_custom_abi});
251 }
